from datetime import datetime

def parse_date(date_str):
    date_obj = datetime.strptime(date_str, '%d %B %Y')
    return {
        'year': date_obj.year,
        'month': date_obj.month,
        'day': date_obj.day
    }

# Example usage:
birth_date = parse_date('31 October 1762')
print(birth_date)  # Output: {'year': 1762, 'month': 10, 'day': 31}
